  ('bookkeeper-moex-00207', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '若國稅局核定遺產稅應納稅額500萬元，下列何種情形納稅義務人不可以申請以實物抵繳？', '["被繼承人遺有銀行存款200萬元", "被繼承人死亡前確有證明在中華民國境內無法收取的債權300萬元", "被繼承人遺有易於變價的上市公司股票100萬元", "納稅義務人所有易於變價的上市公司股票300萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
